#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    if (nums.size() == 1) {
        return 0;
    }

    sort(nums.begin(), nums.end());
    long long min_removed = nums.size();

    for (int i = 0; i < nums.size(); ++i) {
        int left = i;
        int right = nums.size() - 1;
        int pos = -1;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] >= nums[i] * k) {
                pos = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        if (pos != -1) {
            min_removed = min(min_removed, nums.size() - pos - 1);
        }
    }

    return min_removed;
}
